const normalizeText = (value: unknown): string => {
  if (typeof value === "string") return value.replace(/\s+/g, " ").trim();
  if (value === null || value === undefined) return "";
  return String(value).replace(/\s+/g, " ").trim();
};

const readRewardCandidate = (value: unknown): unknown => {
  if (typeof value === "number") return value;
  if (typeof value === "string") {
    const trimmed = value.trim();
    if (!trimmed) return "";
    try {
      return readRewardCandidate(JSON.parse(trimmed) as unknown);
    } catch {
      const match = trimmed.match(/-?\d+(?:\.\d+)?/);
      return match?.[0] ?? trimmed;
    }
  }
  if (value && typeof value === "object" && !Array.isArray(value)) {
    const record = value as Record<string, unknown>;
    return readRewardCandidate(
      record.reward ??
        record.scalar_reward ??
        record.value ??
        record.score ??
        ""
    );
  }
  return "";
};

const rawReward = readRewardCandidate(ctx.locals.carried_output);
const numericReward =
  typeof rawReward === "number" ? rawReward : Number(normalizeText(rawReward));
const reward = Number.isFinite(numericReward) ? numericReward : 0;

return {
  setLocals: {
    reward,
    scalar_reward: reward,
    carried_output: String(reward),
  },
};
